WITH main_q AS (
	SELECT
		q.id AS main_id
	FROM question_db q
	WHERE q.cid = #{c_id,jdbcType=NVARCHAR}
	AND ((q.qtiscon = 1 AND q.ismain = 1) OR q.qtiscon = 0)

		and q.state = #{state}


		AND q.state != 2


		AND q.theme1id = #{th1id,jdbcType=VARCHAR}


		AND q.theme2id = #{th2id,jdbcType=VARCHAR}


		AND q.theme3id = #{th3id,jdbcType=VARCHAR}


		AND q.qtid = #{qtid,jdbcType=VARCHAR}


		AND q.cognitionid_bachelor = #{coid,jdbcType=VARCHAR}


		AND q.difficultyid_bachelor = #{did,jdbcType=VARCHAR}


		AND q.knowledgeid_bachelor = #{kid,jdbcType=VARCHAR}


		AND (floor(sysdate - to_date(q.testtime)) >= #{forbidDay} OR q.testtime IS NULL)


		AND q.num >= #{testNumMin,jdbcType=INTEGER}


		AND q.num <= #{testNumMax,jdbcType=INTEGER}


		AND q.num < #{forbidNum}


		AND dbms_lob.instr(q.content, #{question,jdbcType=VARCHAR}, 1, 1) > 0


		AND EXISTS (
			SELECT 1
			FROM answer_db ad
			WHERE ad.qid = q.id
			AND (
				(ad.atid IN (N'5',N'6',N'7',N'10',N'11',N'12',N'13') AND dbms_lob.instr(ad.content_6, #{answer,jdbcType=VARCHAR}, 1, 1) > 0)
				OR (ad.atid IN (N'0',N'1',N'2',N'3',N'4',N'8',N'9') AND instr(ad.content, #{answer,jdbcType=VARCHAR}) > 0)
			)
		)





				AND q.id IN

					#{item,jdbcType=NVARCHAR}



				AND 1 = 0





		AND EXISTS (
			SELECT 1 FROM teacher tt
			WHERE tt.id = q.creatorid AND tt.real_name LIKE '%' || #{teacher,jdbcType=VARCHAR} || '%'
		)



		AND to_date(#{begindate}, 'yyyy-MM-dd') <= trunc(q.addtime)
		AND to_date(#{enddate}, 'yyyy-MM-dd') >= trunc(q.addtime)

),
picked_q AS (
	SELECT q.id
		FROM question_db q
	JOIN main_q m ON q.id = m.main_id
	WHERE q.cid = #{c_id,jdbcType=NVARCHAR}

	UNION ALL

	SELECT q.id
		FROM question_db q
	JOIN main_q m ON q.mqid = m.main_id
	WHERE q.cid = #{c_id,jdbcType=NVARCHAR} AND q.qtiscon = 1 AND q.ismain = 0
)
SELECT COUNT(*) AS num
FROM picked_q

