select q.id as qid, q.qtiscon as qtiscon, q.content as content, q.mqid as mqid, q.answertime_bachelor as sttime, q.answerid as answerid, q.answertime_bachelor as answertime, q.answerexplain as answerexplain, q.distinction as distinction, q.standard_deviation as standardDeviation, q.realdifficulty as realdifficulty, q.creatorid as creatorid, q.filepath as filepath, t.name as creatorname, vt.name as verifyname, vt.real_name as verifyrealname, t.real_name as creator, q.creatorname as qcreatorname, q.verifyname as qverifyname, ut.real_name as updatorname, ut.name as updator, q.num as num, q.count as qcount, cc.name as coname, cd.name as dname, ck.name as kname, cs.name as soname, qt.qtname as qtname, q.atid as atid, t1.name as t1name, t2.name as t2name, t3.name as t3name from question_db q left join teacher t on q.creatorid=t.id left join teacher vt on q.verifyid = vt.id left join teacher ut on q.updatorid=ut.id left join theme t1 on q.theme1id = t1.id left join theme t2 on q.theme2id = t2.id left join theme t3 on q.theme3id = t3.id left join cognition cc on q.cognitionid_bachelor = cc.id left join difficulty cd on q.difficultyid_bachelor = cd.id left join knowledge ck on q.knowledgeid_bachelor = ck.id left join source cs on q.sourceid = cs.id left join course_questiontype qt on qt.qtid=q.qtid and qt.cid=q.cid where q.cid = #{cid,jdbcType=VARCHAR} and q.mqid is null and q.state != 2
and q.id in
#{item,jdbcType=VARCHAR}
