select count(q.id) as num, min(q.difficultyid_bachelor) as did, min(d.name) as dname from QUESTION_DB q left join difficulty d on q.difficultyid_bachelor=d.id where q.cid = #{id,jdbcType=VARCHAR} and q.ismain = 0 and q.state !=2
and q.state = #{isVerified}
