WITH cid_list AS (
SELECT TO_NCHAR(REGEXP_SUBSTR(#{item,jdbcType=NVARCHAR}, '[^,]+', 1, LEVEL)) AS cid FROM dual CONNECT BY LEVEL <= LENGTH(#{item,jdbcType=NVARCHAR}) - LENGTH(REPLACE(#{item,jdbcType=NVARCHAR}, ',', '')) + 1
), updateWork AS ( SELECT /*+ INLINE */ q.cid, COUNT(*) AS uqcount FROM question_db q JOIN cid_list l ON l.cid = q.cid WHERE q.updatorid IS NOT NULL AND q.ismain = 0 AND q.state != 2
AND q.updatetime >= TO_DATE(#{beginDate},'yyyy-mm-dd') AND q.updatetime < TO_DATE(#{endDate},'yyyy-mm-dd') + 1
GROUP BY q.cid ), createWork AS ( SELECT /*+ INLINE */ q.cid, COUNT(*) AS qcount FROM question_db q JOIN cid_list l ON l.cid = q.cid WHERE q.ismain = 0 AND q.state != 2
AND q.addtime >= TO_DATE(#{beginDate},'yyyy-mm-dd') AND q.addtime < TO_DATE(#{endDate},'yyyy-mm-dd') + 1
GROUP BY q.cid ), c AS ( SELECT c.id, c.name_c,c.unitid,c.deptid FROM course c JOIN cid_list l ON l.cid = c.id
WHERE c.state = #{state} WHERE c.state = 1
) SELECT c.id AS cid, c.name_c AS cname, u.uqcount, cw.qcount,u.name as uname,d.name as deptname FROM c LEFT JOIN updateWork u ON u.cid = c.id LEFT JOIN createWork cw ON cw.cid = c.id LEFT JOIN unit u on u.id=c.unitid LEFT JOIN department d on d.id=c.deptid WHERE 1=1
AND c.unitid = #{unitid,jdbcType=VARCHAR}
AND c.aid = #{arrangeid,jdbcType=VARCHAR}
AND c.deptid = #{depid,jdbcType=VARCHAR}

select case when next_qid = #{id,jdbcType=NVARCHAR} then 'LAST' when prev_qid = #{id,jdbcType=NVARCHAR} then 'NEXT' end as relation, qid, mqid, atid, cid, ismain, iscon from ( select lag(qid) over(order by rn) as prev_qid, lead(qid) over(order by rn) as next_qid, qid, mqid, atid, cid, ismain, qtiscon as iscon from ( select x.*, rownum as rn from (
) x )
where qtiscon = 0 or ismain = 1
) where next_qid = #{id,jdbcType=NVARCHAR} or prev_qid = #{id,jdbcType=NVARCHAR}

